
.world-info {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 14px 18px;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
}

.time-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.time-block {
  display: flex;
  align-items: center;
  gap: 6px;
  color: #c9b8ff;
}

.time-icon {
  font-size: 13px;
  opacity: 0.8;
}

.time-text {
  font-size: 18px;
  font-weight: 700;
  letter-spacing: 0.04em;
  color: #e8deff;
}

.divider-dot {
  width: 4px;
  height: 4px;
  background: rgba(255, 255, 255, 0.25);
  border-radius: 50%;
}

.date-text {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.55);
  letter-spacing: 0.02em;
}

.weekday-text {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.55);
  letter-spacing: 0.02em;
}

.scene-row,
.event-row {
  display: flex;
  align-items: flex-start;
  gap: 8px;
}

.scene-icon {
  font-size: 12px;
  color: #7dd3fc;
  margin-top: 2px;
  flex-shrink: 0;
}

.event-icon {
  font-size: 12px;
  color: #fbbf24;
  margin-top: 2px;
  flex-shrink: 0;
}

.scene-text {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.7);
  line-height: 1.5;
}

.event-text {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.6);
  line-height: 1.5;
}
