
/* ===== 全局根容器 ===== */
.status-root {
  width: 100%;
  padding: 14px 16px 18px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  gap: 14px;

  /* 暗色背景 */
  background: linear-gradient(160deg, #0d0d1a 0%, #12122a 60%, #1a1030 100%);
  border-radius: 16px;
  color: #e8e8f0;
  font-family: 'PingFang SC', 'Microsoft YaHei', sans-serif;
}

/* ===== 男主 OS 块 ===== */
.hero-os-block {
  padding: 12px 16px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.07);
  border-left: 3px solid #a855f7;
  border-radius: 10px;
  cursor: pointer;
  user-select: none;
  transition: background 0.2s, border-color 0.2s;

  &:hover {
    background: rgba(168, 85, 247, 0.06);
    border-color: rgba(168, 85, 247, 0.25);
  }

  &.is-revealed {
    border-left-color: #c084fc;
    background: rgba(168, 85, 247, 0.08);
  }
}

.hero-os-label {
  font-size: 10px;
  color: rgba(255, 255, 255, 0.4);
  letter-spacing: 0.08em;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 5px;
}

.os-hint {
  margin-left: auto;
  font-size: 9px;
  color: rgba(168, 85, 247, 0.6);
  letter-spacing: 0.06em;
  transition: color 0.2s;

  .hero-os-block:hover & {
    color: rgba(168, 85, 247, 0.9);
  }
}

/* 扰码文字 */
.hero-os-glitch {
  font-size: 13px;
  line-height: 1.6;
  color: rgba(168, 85, 247, 0.45);
  font-family: 'Fusion Pixel 12px Mono latin', monospace;
  letter-spacing: 0.05em;
  word-break: break-all;
  animation: glitch-flicker 0.15s steps(1) infinite;
}

@keyframes glitch-flicker {
  0%   { opacity: 1; }
  45%  { opacity: 1; }
  50%  { opacity: 0.7; }
  55%  { opacity: 1; }
  90%  { opacity: 1; }
  95%  { opacity: 0.5; }
  100% { opacity: 1; }
}

/* 真实文字：淡入 */
.hero-os-text {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.78);
  line-height: 1.6;
  animation: os-reveal 0.4s ease;
  user-select: text;
}

@keyframes os-reveal {
  from {
    opacity: 0;
    filter: blur(4px);
  }
  to {
    opacity: 1;
    filter: blur(0);
  }
}

/* ===== 人物卡 Grid ===== */
.heroine-grid {
  display: grid;
  gap: 12px;

  /* 手机竖版：单列 */
  grid-template-columns: 1fr;

  /* 大屏横版：2 列 */
  @media (min-width: 560px) {
    grid-template-columns: repeat(2, 1fr);
  }
}
