
/* ===== 翻牌场景容器 ===== */
.card-scene {
  perspective: 1000px;
  cursor: pointer;
  width: 100%;
  /* 手机：1:1，大屏：4:3 */
  aspect-ratio: 1 / 1;

  @media (min-width: 560px) {
    aspect-ratio: 4 / 3;
  }
}

.card-body {
  width: 100%;
  height: 100%;
  position: relative;
  transform-style: preserve-3d;
  transition: transform 0.6s cubic-bezier(0.4, 0, 0.2, 1);
  border-radius: 14px;

  &.is-flipped {
    transform: rotateY(180deg);
  }
}

/* ===== 正面 / 背面通用 ===== */
.card-face {
  position: absolute;
  inset: 0;
  border-radius: 14px;
  backface-visibility: hidden;
  -webkit-backface-visibility: hidden;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.1);
}

/* ===== 正面 ===== */
.card-front {
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  background: #1a1a2e;
}

.card-cover {
  position: absolute;
  inset: 0;
  opacity: 0.75;
  transition: opacity 0.3s ease;
}

.card-scene:hover .card-cover,
.card-scene:active .card-cover {
  opacity: 1;
}

/* 顶部名字 + 阶段 */
.card-name-badge {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  gap: 3px;
  padding: 12px 14px 0;
}

.card-name {
  font-size: 20px;
  font-weight: 800;
  color: #fff;
  text-shadow: 0 2px 8px rgba(0, 0, 0, 0.6);
  letter-spacing: 0.05em;
}



/* 底部 OS 区 */
.card-os-area {
  position: relative;
  z-index: 1;
  padding: 10px 14px 12px;
  background: linear-gradient(to top, rgba(0, 0, 0, 0.75) 0%, transparent 100%);
}

.os-label {
  font-size: 10px;
  color: rgba(255, 255, 255, 0.5);
  margin-bottom: 4px;
  display: flex;
  align-items: center;
  gap: 4px;
  letter-spacing: 0.04em;
}

.os-text {
  font-size: 12px;
  color: rgba(255, 255, 255, 0.88);
  line-height: 1.5;
  overflow: visible;
}

/* 翻转提示图标 */
.flip-hint {
  position: absolute;
  top: 10px;
  right: 12px;
  z-index: 2;
  color: rgba(255, 255, 255, 0.4);
  font-size: 14px;
  transition: color 0.2s;
}

.card-scene:hover .flip-hint {
  color: rgba(255, 255, 255, 0.8);
}

/* 关系突破按钮 */
.breakthrough-btn {
  position: absolute;
  top: 34px;
  right: 8px;
  z-index: 2;
  background: rgba(236, 72, 153, 0.35);
  border: 1px solid rgba(236, 72, 153, 0.65);
  color: #fbc8e0;
  border-radius: 20px;
  padding: 3px 8px;
  font-size: 11px;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 4px;
  letter-spacing: 0.03em;
  animation: heartbeat 1.2s ease-in-out infinite;
  transition:
    background 0.2s,
    border-color 0.2s,
    color 0.2s;

  &:hover {
    background: rgba(236, 72, 153, 0.38);
    border-color: rgba(236, 72, 153, 0.75);
    color: #fff;
  }
}

@keyframes heartbeat {
  0%, 100% { transform: scale(1); }
  14%       { transform: scale(1.1); }
  28%       { transform: scale(1); }
  42%       { transform: scale(1.06); }
  70%       { transform: scale(1); }
}

/* ===== 背面 ===== */
.card-back {
  transform: rotateY(180deg);
  background: #12122a;
  display: flex;
  flex-direction: column;
  height: 100%;
}

.back-scroll {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  overscroll-behavior-y: contain;
  padding: 12px 14px;
  scrollbar-width: thin;
  scrollbar-color: rgba(255, 255, 255, 0.15) transparent;

  &::-webkit-scrollbar {
    width: 4px;
  }
  &::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.15);
    border-radius: 2px;
  }
}

/* 背面标题栏 */
.back-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 12px;
}

.back-name {
  font-size: 16px;
  font-weight: 700;
  color: #e8deff;
  letter-spacing: 0.06em;
}

.flip-back-btn {
  background: rgba(255, 255, 255, 0.08);
  border: none;
  color: rgba(255, 255, 255, 0.5);
  width: 24px;
  height: 24px;
  border-radius: 50%;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  transition:
    background 0.2s,
    color 0.2s;

  &:hover {
    background: rgba(255, 255, 255, 0.15);
    color: rgba(255, 255, 255, 0.9);
  }
}

/* 区块标题 */
.section-title {
  font-size: 11px;
  color: rgba(255, 255, 255, 0.45);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 5px;
}

/* 每行数据：section 用 grid，label 列宽度由最长内容自动撑开 */
.back-section {
  display: grid;
  /* label 列：max-content 自动对齐到本 section 内最宽的 label；value 列占剩余 */
  grid-template-columns: max-content 1fr;
  column-gap: 10px;
  row-gap: 5px;
  align-items: start;
  font-size: 12px;
  line-height: 1.4;
}

/* section-title 和 intimacy-bar 要横跨两列 */
.section-title,
.intimacy-bar {
  grid-column: 1 / -1;
}

.back-row {
  /* back-row 本身作为子网格行，label 和 value 直接是它的子元素 */
  display: contents;
}

.back-label {
  color: rgba(255, 255, 255, 0.45);
  display: flex;
  align-items: baseline;
  gap: 4px;
  white-space: nowrap;
}

.back-value {
  color: rgba(255, 255, 255, 0.82);
  word-break: break-all;
}

.back-value--with-badge {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 6px;
}

.insert-badge {
  flex-shrink: 0;
  font-size: 0.75em;
  color: rgba(255, 255, 255, 0.4);
  background: rgba(255, 255, 255, 0.07);
  border-radius: 4px;
  padding: 1px 5px;
  letter-spacing: 0.02em;
}

/* 关系阶段 badge */
.stage-badge {
  display: inline-block;
  background: rgba(168, 85, 247, 0.2);
  border: 1px solid rgba(168, 85, 247, 0.4);
  color: #c084fc;
  padding: 1px 8px;
  border-radius: 20px;
  font-size: 11px;
}

/* 专属属性高亮（独立 section 用，现已移除，保留备用） */
.special-attr {
  color: #fbbf24;
}

/* 进度条行内专属属性 */
.special-attr-inline {
  font-size: 12px;
  white-space: nowrap;
}

.special-attr-key {
  color: rgba(255, 255, 255, 0.45); /* 与 .back-label 一致 */
}

.special-attr-val {
  color: #fbbf24;
}

/* 亲密度块 */
.intimacy-block {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.intimacy-header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 8px;
  font-size: 12px;
}

.intimacy-stage {
  color: rgba(255, 255, 255, 0.82);
  white-space: nowrap;
}

/* 阶段进度进度条 */
.intimacy-bar {
  width: 100%;
  height: 4px;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 2px;
  overflow: hidden;
  margin-top: 2px;

  /* 阶段1：绿色主题 */
  &.stage-1 .intimacy-fill {
    background: linear-gradient(90deg, #22c55e, #4ade80);
  }

  /* 阶段2：黄色主题 */
  &.stage-2 .intimacy-fill {
    background: linear-gradient(90deg, #f59e0b, #fbbf24);
  }

  /* 阶段3：玫红主题 */
  &.stage-3 .intimacy-fill {
    background: linear-gradient(90deg, #ec4899, #f472b6);
  }
}

.intimacy-fill {
  height: 100%;
  border-radius: 2px;
  transition: width 0.4s ease;
}

/* 隐秘身份行 */
.hidden-id-row {
  font-size: 11px;
  color: rgba(255, 255, 255, 0.4);
  display: flex;
  align-items: center;
  gap: 5px;
  margin-top: 4px;
  letter-spacing: 0.03em;
  line-height: 1.4;
}

/* 分割线 */
.section-divider {
  height: 1px;
  background: rgba(255, 255, 255, 0.07);
  margin: 8px 0;
}

/* ===== 突破剧情待触发状态 ===== */
.stage-breakthrough {
  color: #f87171;
  animation: stage-shake 0.35s steps(1) infinite;
  display: inline-flex;
  align-items: baseline;
  gap: 4px;
}

.stage-breakthrough-icon {
  font-size: 10px;
  flex-shrink: 0;
}

.stage-breakthrough-bar .intimacy-fill {
  background: linear-gradient(90deg, #dc2626, #f87171) !important;
}

/* 每帧跳变（steps(1)），xy 双轴随机幅度 0~1px，无平滑过渡 */
@keyframes stage-shake {
  0%   { transform: translate(  1px,  0px); }
  9%   { transform: translate(  0px,  1px); }
  18%  { transform: translate( -1px,  0px); }
  27%  { transform: translate(  0px, -1px); }
  36%  { transform: translate(  1px,  1px); }
  45%  { transform: translate( -1px,  0px); }
  54%  { transform: translate(  0px,  1px); }
  63%  { transform: translate(  1px, -1px); }
  72%  { transform: translate(  0px,  0px); }
  81%  { transform: translate( -1px,  1px); }
  90%  { transform: translate(  1px,  0px); }
  100% { transform: translate(  0px, -1px); }
}
